import 'package:vector_math/vector_math.dart' show Vector2;

/// Shared CPU-render viewport mapping.
///
/// Pixel coordinates are edge-inclusive for iteration buffers, preserving the
/// existing scalar-field/golden contract. Subpixel sample coordinates are
/// center-of-pixel positions and must stay inside the same [-1, 1] viewport.
final class CpuViewportMapping {
  final double centerX;
  final double centerY;
  final double scale;
  final double aspect;

  CpuViewportMapping({
    required Vector2 viewPan,
    required double viewZoom,
    required int width,
    required int height,
  }) : this.fromScalars(
          panX: viewPan.x,
          panY: viewPan.y,
          viewZoom: viewZoom,
          width: width,
          height: height,
        );

  CpuViewportMapping.fromScalars({
    required double panX,
    required double panY,
    required double viewZoom,
    required int width,
    required int height,
  })  : centerX = panX,
        centerY = panY,
        scale = 1.5 / normalizeZoom(viewZoom),
        aspect = height == 0 ? 1.0 : width / height;

  static double normalizeZoom(double zoom) {
    if (zoom.isNaN || zoom <= 0.0) return 1.0;
    return zoom;
  }

  double normalizedPixel(int pixel, int extent) {
    if (extent <= 1) return 0.0;
    return (pixel / (extent - 1)) * 2.0 - 1.0;
  }

  double normalizedSample({
    required int pixel,
    required int extent,
    required int sample,
    required int samplesPerAxis,
  }) {
    final safeSamples = samplesPerAxis <= 0 ? 1 : samplesPerAxis;
    final safeSample = sample.clamp(0, safeSamples - 1).toInt();
    return normalizedSampleOffset(
      pixel: pixel,
      extent: extent,
      sampleOffset: (safeSample + 0.5) / safeSamples,
    );
  }

  double normalizedSampleOffset({
    required int pixel,
    required int extent,
    required double sampleOffset,
  }) {
    if (extent <= 1) return 0.0;
    final safePixel = pixel.clamp(0, extent - 1).toInt();
    final safeOffset =
        sampleOffset.isNaN ? 0.5 : sampleOffset.clamp(0.0, 1.0).toDouble();
    final subPixel = safePixel + safeOffset;
    return (subPixel / extent) * 2.0 - 1.0;
  }

  (double x, double y) coordinate({required double nx, required double ny}) {
    return (centerX + nx * scale * aspect, centerY + ny * scale);
  }
}

import 'package:flutter_fractals/features/renderer/cpu_fractal_renderer.dart';
import 'package:flutter_fractals/features/renderer/cpu_render_isolate.dart';
import 'package:flutter_fractals/features/renderer/cpu_viewport_mapping.dart';
import 'package:flutter_test/flutter_test.dart';
import 'package:vector_math/vector_math.dart' show Vector2;

void main() {
  group('CPU viewport mapping', () {
    test('subpixel samples stay inside the normalized viewport', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(-0.5, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 0,
          samplesPerAxis: 1,
        ),
        closeTo(0.5, 1e-12),
      );
    });

    test('invalid subpixel sample candidates clamp to the pixel footprint', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(
        viewport.normalizedSample(
          pixel: 1,
          extent: 2,
          sample: 4,
          samplesPerAxis: 2,
        ),
        closeTo(0.75, 1e-12),
      );
      expect(
        viewport.normalizedSample(
          pixel: 0,
          extent: 2,
          sample: -1,
          samplesPerAxis: 2,
        ),
        closeTo(-0.75, 1e-12),
      );
    });

    test('edge pixels preserve iteration-buffer edge-inclusive contract', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: 1.0,
        width: 2,
        height: 2,
      );

      expect(viewport.normalizedPixel(0, 2), -1.0);
      expect(viewport.normalizedPixel(1, 2), 1.0);
    });

    test('invalid zoom falls back to replayable unit-scale coordinates', () {
      final viewport = CpuViewportMapping(
        viewPan: Vector2.zero(),
        viewZoom: double.nan,
        width: 2,
        height: 2,
      );

      expect(viewport.scale, 1.5);
      expect(viewport.coordinate(nx: 0.5, ny: -0.5), (0.75, -0.75));
    });

    test('isolate sample mapping shares invalid zoom normalization', () {
      final coordinate = cpuViewportCoordinateForSample(
        panX: 0.0,
        panY: 0.0,
        zoom: double.nan,
        fullWidth: 2,
        fullHeight: 2,
        x: 1,
        y: 0,
        sampleOffsetX: 0.5,
        sampleOffsetY: 0.5,
      );

      expect(coordinate.x, 0.75);
      expect(coordinate.y, -0.75);
    });

    test('single-pixel iteration buffer samples the viewport center', () async {
      final buffer = await renderCpuIterationBuffer(
        moduleId: 'mandelbrot',
        viewPan: Vector2(-0.5, 0.0),
        viewZoom: 1.0,
        iterations: 50,
        bailout: 4.0,
        juliaC: Vector2(-0.8, 0.156),
        width: 1,
        height: 1,
      );

      expect(buffer, isNotNull);
      expect(buffer!.single, 50);
    });
  });
}

import 'dart:async';
import 'dart:isolate';

import 'cpu_render_isolate.dart';

/// A long-lived isolate for CPU tile rendering.
///
/// Spawning an isolate per tile (Isolate.run) is far too slow on mobile.
/// This worker keeps one isolate alive and processes tile jobs sequentially.
class CpuTileWorker {
  CpuTileWorker._(this._isolate, this._sendPort, this._sub);

  final Isolate _isolate;
  final SendPort _sendPort;
  final StreamSubscription _sub;

  static Future<CpuTileWorker> spawn() async {
    final receive = ReceivePort();
    final handshake = Completer<SendPort>();

    final sub = receive.listen((msg) {
      if (msg is SendPort && !handshake.isCompleted) {
        handshake.complete(msg);
      }
    });

    final isolate = await Isolate.spawn(_entry, receive.sendPort);
    final sendPort = await handshake.future;

    return CpuTileWorker._(isolate, sendPort, sub);
  }

  Future<CpuTileRenderResponse> renderTile(CpuTileRenderRequest req) async {
    final rp = ReceivePort();
    _sendPort.send((req, rp.sendPort));
    final msg = await rp.first;
    rp.close();
    return msg as CpuTileRenderResponse;
  }

  void dispose() {
    _sub.cancel();
    _isolate.kill(priority: Isolate.immediate);
  }
}

void _entry(SendPort mainSendPort) {
  final commands = ReceivePort();
  mainSendPort.send(commands.sendPort);

  commands.listen((msg) {
    final (CpuTileRenderRequest req, SendPort replyTo) = msg as (CpuTileRenderRequest, SendPort);
    final resp = renderCpuTileInIsolate(req);
    replyTo.send(resp);
  });
}

